mapper.select:
SELECT ir.result_id, ir.schedule_id, ir.user_id, ir.decision, ir.assigned_dept_id, ir.decision_by, ir.decision_at, ir.created_at, ir.updated_at, isc.cycle_id, u.name as user_name, d.dept_name as department_name FROM interview_result ir LEFT JOIN interview_schedule isc ON ir.schedule_id = isc.schedule_id LEFT JOIN user u ON ir.user_id = u.user_id LEFT JOIN department d ON ir.assigned_dept_id = d.dept_id
AND isc.cycle_id = #{cycleId}
AND u.name LIKE CONCAT('%', #{name}, '%')
AND ir.decision = #{decision}
AND d.name LIKE CONCAT('%', #{department}, '%')
ORDER BY ir.created_at DESC
